    for (let mask = 1; mask < (1 << n); mask++) {
        // 1. Check if the sum of values in the subset is even
        let sum = 0;
        for (let i = 0; i < n; i++) {
            if ((mask & (1 << i)) !== 0) {
                sum += nums[i];
            }
        }

        if (sum % 2 !== 0) {
            continue; // Sum must be even
        }

        // 2. Check if the induced subgraph is connected

        // Find the first node in the subset to start BFS/DFS from
        let startNode = -1;
        for (let i = 0; i < n; i++) {
