        const queue: number[] = [startNode];
        visited[startNode] = true;
        let visitedCount = 1;

        while (queue.length > 0) {
            const u = queue.shift()!;

            for (let v = 0; v < n; v++) {
                // Check 1: v must be in the subset (mask)
                if ((mask & (1 << v)) === 0) continue;

                // Check 2: v must not be visited
