                // Check if (u, v) is an edge AND v hasn't been visited yet
                if (adjMatrix[u][v] && !visited.has(v)) {
                    visited.add(v);
                    visitedCount++;
                    queue.push(v);
                }
            }
        }

        // If the number of nodes reached equals the size of the subset, it is connected
        if (visitedCount === nodesInSubset.length) {
            count++;
        }
    }

    return count;
}
